# Registre de playbooks : associe un type d'alerte à un playbook
REGISTRE_PLAYBOOKS = {}

def enregistrer_playbook(type_alerte):
    """Décorateur pour enregistrer un playbook."""
    def decorator(fn):
        REGISTRE_PLAYBOOKS[type_alerte] = fn
        return fn
    return decorator

@enregistrer_playbook("BRUTE_FORCE_SSH")
def playbook_ssh(alerte):
    return executer_playbook("Brute Force SSH", PLAYBOOK_BRUTE_FORCE, alerte)

@enregistrer_playbook("MALWARE_DETECTED")
def playbook_malware(alerte):
    print(f"\n=== Playbook Malware ===")
    print(f"Machine {alerte.get('host')} — Isolation en cours (simulation)")
    print(f"Hash : {alerte.get('hash')}")
    print("Actions : isoler machine, collecter forensics, notifier")
    return {"succes": True}

def router_alerte(alerte):
    """Route une alerte vers le bon playbook."""
    type_alerte = alerte.get("type", "INCONNU")
    playbook_fn = REGISTRE_PLAYBOOKS.get(type_alerte)

    if playbook_fn:
        print(f"Routage → {type_alerte}")
        return playbook_fn(alerte)
    else:
        print(f"Aucun playbook pour {type_alerte} — escalade manuelle")
        return None

# Test du routage
alertes_entrees = [
    {"type": "BRUTE_FORCE_SSH", "ip": "185.220.101.3"},
    {"type": "MALWARE_DETECTED", "host": "WORKSTATION-42", "hash": "d41d8cd9..."},
    {"type": "INCONNU", "ip": "1.2.3.4"},
]
for a in alertes_entrees:
    router_alerte(a)
    print()
